"""Funciones de reporting para el experimento federado."""from __future__ import annotationsfrom pathlib import Pathfrom typing import Sequenceimport matplotlib.pyplot as pltimport numpy as npimport pandas as pdfrom sklearn.metrics import classification_reportdef save_history(history_df: pd.DataFrame, history_path: Path) -> None:    """    Guarda el histórico de métricas en formato CSV.    Parameters    ----------    history_df : pd.DataFrame        DataFrame con la evolución de métricas por ronda.    history_path : Path        Ruta del fichero CSV de salida.    """    history_path.parent.mkdir(parents=True, exist_ok=True)    history_df.to_csv(history_path, index=False)def plot_history(history_df: pd.DataFrame, plot_path: Path, show: bool = True) -> None:    """    Dibuja y guarda la evolución de las métricas del modelo global.    Parameters    ----------    history_df : pd.DataFrame        DataFrame con las métricas por ronda.    plot_path : Path        Ruta de salida para la figura.    show : bool        Si es True, muestra la figura además de guardarla.    """    plot_path.parent.mkdir(parents=True, exist_ok=True)    plt.figure(figsize=(10, 6))    plt.plot(history_df["round"], history_df["accuracy"], marker="o", label="Accuracy")    plt.plot(        history_df["round"],        history_df["balanced_accuracy"],        marker="o",        label="Balanced Accuracy",    )    plt.plot(history_df["round"], history_df["macro_f1"], marker="o", label="Macro F1")    plt.xlabel("Ronda federada")    plt.ylabel("Métrica")    plt.title("Evolución del modelo global")    plt.grid(True, alpha=0.3)    plt.legend()    plt.tight_layout()    plt.savefig(plot_path, dpi=150)    if show:        plt.show()    plt.close()def plot_confusion_matrix(    cm: np.ndarray,    labels: Sequence[str],    plot_path: Path,    show: bool = True,) -> None:    """    Dibuja y guarda una matriz de confusión.    Parameters    ----------    cm : np.ndarray        Matriz de confusión.    labels : Sequence[str]        Etiquetas de clase.    plot_path : Path        Ruta de salida para la figura.    show : bool        Si es True, muestra la figura además de guardarla.    """    plot_path.parent.mkdir(parents=True, exist_ok=True)    plt.figure(figsize=(9, 7))        # 1. Cambiamos el mapa de colores a 'Blues'    plt.imshow(cm, interpolation="nearest", cmap=plt.cm.Blues)        plt.title("Matriz de confusión")    plt.colorbar()    tick_marks = np.arange(len(labels))    plt.xticks(tick_marks, labels, rotation=45, ha="right")    plt.yticks(tick_marks, labels)    # 2. Ajustamos el umbral para el contraste del texto    # Usamos cm.max() / 2 para dividir el texto en blanco o negro según el fondo    threshold = cm.max() / 2.0     for row_idx in range(cm.shape[0]):        for col_idx in range(cm.shape[1]):            # 3. Ajustamos el color del texto            # En 'Blues', las celdas oscuras tienen valores altos -> texto blanco            # Las celdas claras tienen valores bajos -> texto negro            plt.text(                col_idx,                row_idx,                format(cm[row_idx, col_idx], "d"),                ha="center",                va="center",                color="white" if cm[row_idx, col_idx] > threshold else "black",            )    plt.ylabel("Etiqueta real")    plt.xlabel("Etiqueta predicha")    plt.tight_layout()    plt.savefig(plot_path, dpi=150)    if show:        plt.show()    plt.close()def build_classification_report_text(    y_true: Sequence[str],    y_pred: Sequence[str],    labels: Sequence[str],) -> str:    """    Genera el classification report en formato texto.    Parameters    ----------    y_true : Sequence[str]        Etiquetas reales.    y_pred : Sequence[str]        Etiquetas predichas.    labels : Sequence[str]        Orden de las etiquetas.    Returns    -------    str        Texto del classification report.    """    return classification_report(        y_true,        y_pred,        labels=labels,        zero_division=0,    )def save_text_report(report_text: str, report_path: Path) -> None:    """    Guarda un informe de texto en disco.    Parameters    ----------    report_text : str        Texto del informe.    report_path : Path        Ruta de salida.    """    report_path.parent.mkdir(parents=True, exist_ok=True)    with open(report_path, "w", encoding="utf-8") as file:        file.write(report_text)def print_final_summary(    history_df: pd.DataFrame,    best_balanced_round: int,    best_macro_f1_round: int,    final_metrics: dict[str, float],    best_bal_metrics: dict[str, float],    best_f1_metrics: dict[str, float],    report_text: str,    tail_rows: int = 10,) -> None:    """    Imprime por pantalla el resumen final del experimento.    Parameters    ----------    history_df : pd.DataFrame        Histórico de métricas por ronda.    best_balanced_round : int        Ronda del mejor modelo por balanced accuracy.    best_macro_f1_round : int        Ronda del mejor modelo por macro F1.    final_metrics : dict[str, float]        Métricas del modelo final.    best_bal_metrics : dict[str, float]        Métricas del mejor modelo por balanced accuracy.    best_f1_metrics : dict[str, float]        Métricas del mejor modelo por macro F1.    report_text : str        Texto del classification report.    tail_rows : int        Número de filas finales del histórico que se mostrarán.    """    print("\n=== RESUMEN FINAL ===")    print(history_df.tail(tail_rows).to_string(index=False))    print("\n=== MEJOR CHECKPOINT ===")    print(        f"Mejor balanced_accuracy: ronda {best_balanced_round} | "        f"acc={best_bal_metrics['accuracy']:.4f} | "        f"bal_acc={best_bal_metrics['balanced_accuracy']:.4f} | "        f"macro_f1={best_bal_metrics['macro_f1']:.4f}"    )    print(        f"Mejor macro_f1: ronda {best_macro_f1_round} | "        f"acc={best_f1_metrics['accuracy']:.4f} | "        f"bal_acc={best_f1_metrics['balanced_accuracy']:.4f} | "        f"macro_f1={best_f1_metrics['macro_f1']:.4f}"    )    print(        f"Modelo final: "        f"acc={final_metrics['accuracy']:.4f} | "        f"bal_acc={final_metrics['balanced_accuracy']:.4f} | "        f"macro_f1={final_metrics['macro_f1']:.4f}"    )    print("\n=== CLASSIFICATION REPORT (mejor balanced_accuracy) ===")    print(report_text)